import { ref, watch } from 'vue';
import { ElMessage } from 'element-plus';
export default {
  __name: 'EditSkillDialog',
  props: {
    modelValue: Boolean,
    initialData: {
      type: Object,
      default: () => ({
        name: '',
        // 提供默认值
        level: '',
        description: ''
      })
    },
    loading: Boolean
  },
  emits: ['update:modelValue', 'submit'],
  setup(__props, {
    expose: __expose,
    emit: __emit
  }) {
    __expose();
    const props = __props;
    const emit = __emit;
    const dialogVisible = ref(false);
    const formRef = ref(null);

    // 表单数据
    const formData = ref({
      name: '',
      level: '',
      description: ''
    });

    // 监听初始数据变化
    watch(() => props.initialData, val => {
      if (val) {
        formData.value = {
          name: val.name || '',
          // 确保有默认值
          level: val.level || '',
          description: val.description || ''
        };
      } else {
        formData.value = {
          name: '',
          level: '',
          description: ''
        };
      }
    }, {
      immediate: true
    });

    // ... 其他代码

    const __returned__ = {
      props,
      emit,
      dialogVisible,
      formRef,
      formData,
      ref,
      watch,
      get ElMessage() {
        return ElMessage;
      }
    };
    Object.defineProperty(__returned__, '__isScriptSetup', {
      enumerable: false,
      value: true
    });
    return __returned__;
  }
};
